#!/usr/bin/env node

// Codex environment bootstrap (#670): applies the repo-side Codex policy
// layer to an arbitrary repository so the rollout to other repos needs no
// re-derivation. Image Trail is the pilot; the generated files here are the
// reference output.
//
// Invariants (identical in every repo): .codex/config.toml execution policy,
// .codex/hooks.json PreToolUse guard hook, the generic direct-runner
// forbidden rules, and the environment.toml skeleton (Node from .nvmrc,
// lockfile-driven install, fatal initial build).
// Parameters (derived per repo, never hand-tuned): the npm scripts that are
// guarded entrypoints (detected by their use of run-guarded.mjs), their
// unguarded :inner/:run implementation details, and human-only interactive
// scripts (guarded with --timeout-s 0).
//
// Usage:
//   node scripts/bootstrap-codex-env.mjs [--repo <path>] [--force] [--check]
//
// --check validates an existing setup instead of writing: files present,
// every test script guarded, rules verified against the local `codex` CLI
// when one is available. Always prints the manual steps that cannot be
// automated (project trust, one-time hook trust, Desktop/cloud settings).
//
// Prerequisite: the shared guard slice — scripts/run-guarded.mjs and
// scripts/guard-agent-command.mjs — must already exist in the target repo.

import { execFileSync } from 'node:child_process';
import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs';
import path from 'node:path';
import process from 'node:process';
import { pathToFileURL } from 'node:url';

const args = process.argv.slice(2);
const flag = (name) => args.includes(name);
const option = (name) => {
  const index = args.indexOf(name);
  return index !== -1 && index + 1 < args.length ? args[index + 1] : undefined;
};

const repoRoot = path.resolve(option('--repo') ?? process.cwd());
const checkOnly = flag('--check');
const force = flag('--force');

const problems = [];
const notes = [];

function fail(message) {
  problems.push(message);
}

function note(message) {
  notes.push(message);
}

function readJson(filePath) {
  return JSON.parse(readFileSync(filePath, 'utf8'));
}

// --- Derive per-repo parameters from package.json ---------------------------

function deriveScriptSets(packageJson) {
  const scripts = packageJson.scripts ?? {};
  const guarded = [];
  const inner = [];
  const humanOnly = [];

  for (const [name, command] of Object.entries(scripts)) {
    if (command.includes('run-guarded.mjs')) {
      if (/--timeout-s\s+0\b/.test(command)) humanOnly.push(name);
      else guarded.push(name);
      continue;
    }
    if (/^test([:.]|$)/.test(name) && /:(inner|run)$/.test(name)) inner.push(name);
  }

  return { guarded, inner, humanOnly };
}

// Generic direct runners that bypass any repo's guard. Invariant list; a rule
// for a tool the repo does not use is inert.
const DIRECT_RUNNER_FORBIDS = [
  { pattern: ['node', '--test'], hint: 'use the guarded npm test entrypoints' },
  { pattern: ['npx', 'playwright', 'test'], hint: 'use the guarded e2e entrypoint' },
  { pattern: ['playwright', 'test'], hint: 'use the guarded e2e entrypoint' },
  { pattern: ['npx', 'c8'], hint: 'use the guarded coverage entrypoint' },
  { pattern: ['c8'], hint: 'use the guarded coverage entrypoint' },
  { pattern: ['npx', 'test-storybook'], hint: 'use the guarded stories entrypoint' },
  { pattern: ['test-storybook'], hint: 'use the guarded stories entrypoint' },
  { pattern: ['npx', 'vitest'], hint: 'use the guarded npm test entrypoints' },
  { pattern: ['vitest'], hint: 'use the guarded npm test entrypoints' },
  { pattern: ['npx', 'jest'], hint: 'use the guarded npm test entrypoints' },
  { pattern: ['jest'], hint: 'use the guarded npm test entrypoints' },
];

// Bounded non-test gates that are safe to auto-allow when present.
const AUTO_ALLOW_GATES = ['lint', 'format:check', 'typecheck', 'build', 'ci'];

function renderRule(pattern, decision, justification) {
  const tokens = pattern.map((token) => JSON.stringify(token)).join(', ');
  if (!justification) return `prefix_rule(pattern = [${tokens}], decision = ${JSON.stringify(decision)})`;
  return (
    `prefix_rule(\n` +
    `    pattern = [${tokens}],\n` +
    `    decision = ${JSON.stringify(decision)},\n` +
    `    justification = ${JSON.stringify(justification)},\n` +
    `)`
  );
}

function renderRules({ guarded, inner, humanOnly }, packageJson) {
  const lines = [
    '# Codex execpolicy rules — GENERATED by scripts/bootstrap-codex-env.mjs.',
    '# Regenerate after changing test-related npm scripts; do not hand-edit the',
    '# generated sections. Loaded only when the project .codex/ layer is',
    '# trusted; most-restrictive decision wins. Validate with:',
    '#   codex execpolicy check --rules .codex/rules/process-guard.rules -- <cmd…>',
    '',
    '# --- Forbidden: direct test runners that bypass the guard (invariant) ---',
    '',
  ];
  for (const { pattern, hint } of DIRECT_RUNNER_FORBIDS) {
    lines.push(renderRule(pattern, 'forbidden', `Bypasses the process-tree memory guard; ${hint}.`), '');
  }
  lines.push('# --- Forbidden: unguarded inner scripts and human-only runs (derived) ---', '');
  for (const name of inner) {
    lines.push(renderRule(['npm', 'run', name], 'forbidden', 'Inner npm script skips the guard; use the guarded entrypoint.'), '');
  }
  for (const name of humanOnly) {
    lines.push(renderRule(['npm', 'run', name], 'forbidden', "Interactive/headed run steals the user's desktop focus; human-only."), '');
  }
  lines.push('# --- Allowed: guarded entrypoints and bounded gates (derived) ---', '');
  if ((packageJson.scripts ?? {}).test?.includes('run-guarded.mjs')) {
    lines.push(renderRule(['npm', 'test'], 'allow'));
  }
  for (const name of guarded) {
    if (name === 'test') continue;
    lines.push(renderRule(['npm', 'run', name], 'allow'));
  }
  for (const name of AUTO_ALLOW_GATES) {
    if ((packageJson.scripts ?? {})[name]) lines.push(renderRule(['npm', 'run', name], 'allow'));
  }
  lines.push('');
  return lines.join('\n');
}

// --- Invariant templates -----------------------------------------------------

const CONFIG_TOML = `# Project-scoped Codex config — managed by scripts/bootstrap-codex-env.mjs.
# Loaded (CLI + Desktop + IDE) only when the project is trusted
# (projects.<path>.trust_level = "trusted" in ~/.codex/config.toml). Keys like
# notify/model_provider are user-side only and ignored here by design.
# Companion layers in this directory:
#   rules/process-guard.rules — hard-forbids unguarded test runners
#   hooks.json               — PreToolUse deny for variants rules cannot match
#   environments/environment.toml — Desktop worktree setup/cleanup
approval_policy = "on-request"

# Filesystem containment: writes stay inside the workspace (plus /tmp and
# $TMPDIR). <root>/.git, <root>/.codex, and <root>/.agents remain read-only
# inside the sandbox, so an agent cannot edit its own policy layers. This does
# NOT cap memory — the process-tree guard (scripts/run-guarded.mjs) is the
# memory control.
sandbox_mode = "workspace-write"

[sandbox_workspace_write]
# Dependency installs and browser downloads need outbound network in the dev
# loop; the guard is a resource backstop, not an exfiltration control.
network_access = true

[features]
# Hooks are stable-on in current Desktop builds; pinned so older CLI installs
# load .codex/hooks.json too instead of silently skipping it.
hooks = true
`;

const HOOKS_JSON = `${JSON.stringify(
  {
    description:
      'Process-tree guard: deny shell commands that bypass scripts/run-guarded.mjs. Complements .codex/rules/process-guard.rules; requires one-time trust via /hooks.',
    hooks: {
      PreToolUse: [
        {
          matcher: 'Bash',
          hooks: [
            {
              type: 'command',
              command: 'node "$(git rev-parse --show-toplevel)/scripts/guard-agent-command.mjs" --protocol=codex',
              timeout: 30,
              statusMessage: 'Checking command against the process-tree guard policy',
            },
          ],
        },
      ],
    },
  },
  null,
  2,
)}\n`;

function renderEnvironmentToml(name) {
  return `# Codex Desktop local environment — applied by scripts/bootstrap-codex-env.mjs.
# Read by the Desktop app when provisioning a managed worktree; Codex cloud
# does not read it (mirror [setup] at chatgpt.com/codex/settings/environments).
version = 1
name = ${JSON.stringify(name)}

[setup]
script = '''
set -Eeuo pipefail
if git rev-parse --show-toplevel >/dev/null 2>&1; then
  cd "$(git rev-parse --show-toplevel)"
fi
export NVM_DIR="\${NVM_DIR:-$HOME/.nvm}"
[ -s "$NVM_DIR/nvm.sh" ] && . "$NVM_DIR/nvm.sh"
if [ -f .nvmrc ] && command -v nvm >/dev/null 2>&1; then
  nvm install && nvm use && nvm alias default "$(nvm current)"
fi
if [ -f package-lock.json ]; then
  npm ci --no-audit --no-fund
elif [ -f package.json ]; then
  npm install
fi
if [ -f package.json ] && npm run | grep -qE '^[[:space:]]+build$'; then
  npm run build
fi
'''
`;
}

// --- Apply / check -----------------------------------------------------------

function writeManaged(relativePath, content) {
  const target = path.join(repoRoot, relativePath);
  if (existsSync(target)) {
    const current = readFileSync(target, 'utf8');
    if (current === content) {
      note(`${relativePath}: up to date`);
      return;
    }
    if (!force) {
      fail(`${relativePath}: exists with different content (rerun with --force to overwrite)`);
      return;
    }
  }
  mkdirSync(path.dirname(target), { recursive: true });
  writeFileSync(target, content);
  note(`${relativePath}: written`);
}

function checkRulesWithCodex(rulesPath) {
  let codexBinary = 'codex';
  try {
    execFileSync(codexBinary, ['--version'], { stdio: 'ignore' });
  } catch {
    note('codex CLI not on PATH; skipped execpolicy verification (run it where codex is installed)');
    return;
  }
  const probes = [
    { argv: ['node', '--test', 'x.test.js'], expected: 'forbidden' },
    { argv: ['npx', 'playwright', 'test'], expected: 'forbidden' },
    { argv: ['npm', 'test'], expected: 'allow' },
  ];
  for (const { argv, expected } of probes) {
    try {
      const output = execFileSync(codexBinary, ['execpolicy', 'check', '--rules', rulesPath, '--', ...argv], { encoding: 'utf8' });
      const decision = JSON.parse(output).decision ?? 'no-match';
      if (decision !== expected) {
        fail(`execpolicy probe ${argv.join(' ')}: expected ${expected}, got ${decision}`);
      } else {
        note(`execpolicy probe ${argv.join(' ')}: ${decision}`);
      }
    } catch (error) {
      fail(`execpolicy probe ${argv.join(' ')} failed to run: ${error.message ?? error}`);
    }
  }
}

async function main() {
  const packagePath = path.join(repoRoot, 'package.json');
  if (!existsSync(packagePath)) {
    console.error(`No package.json in ${repoRoot}; pass --repo <path> to the repo root.`);
    process.exit(1);
  }
  const packageJson = readJson(packagePath);
  const repoName = (packageJson.name ?? path.basename(repoRoot)).replace(/^@[^/]+\//, '');

  for (const prerequisite of ['scripts/run-guarded.mjs', 'scripts/guard-agent-command.mjs']) {
    if (!existsSync(path.join(repoRoot, prerequisite))) {
      fail(`${prerequisite} missing — apply the shared guard slice first (Image Trail PR #674).`);
    }
  }
  if (!existsSync(path.join(repoRoot, '.nvmrc'))) {
    note('.nvmrc missing — the environment setup script will fall back to the ambient Node.');
  }

  const sets = deriveScriptSets(packageJson);
  if (sets.guarded.length === 0) {
    fail('No npm scripts invoke run-guarded.mjs; guard the test entrypoints before bootstrapping.');
  }

  // A guarded script here or an :inner name is accounted for; any OTHER script
  // that directly invokes a raw test runner is an unguarded entrypoint the
  // hook cannot see (it only observes `npm run <name>`), so the bootstrap
  // refuses until the script is wrapped in run-guarded.mjs (or renamed
  // :inner/:run if it is guard-internal). Classification reuses the hook's own
  // deny regexes so the two layers can never disagree.
  const guardHookPath = path.join(repoRoot, 'scripts/guard-agent-command.mjs');
  if (existsSync(guardHookPath)) {
    const { evaluateCommand } = await import(pathToFileURL(guardHookPath).href);
    const accounted = new Set([...sets.guarded, ...sets.humanOnly, ...sets.inner]);
    for (const [name, command] of Object.entries(packageJson.scripts ?? {})) {
      if (accounted.has(name)) continue;
      if (!evaluateCommand(command).allow) {
        fail(
          `npm script "${name}" invokes a raw test runner unguarded — wrap it in ` +
            'run-guarded.mjs (or use an :inner/:run suffix if it is guard-internal).',
        );
      }
    }
  }

  const rulesContent = renderRules(sets, packageJson);
  const rulesRelative = '.codex/rules/process-guard.rules';

  if (checkOnly) {
    for (const relativePath of ['.codex/config.toml', '.codex/hooks.json', rulesRelative]) {
      if (!existsSync(path.join(repoRoot, relativePath))) fail(`${relativePath}: missing`);
      else note(`${relativePath}: present`);
    }
    const rulesPath = path.join(repoRoot, rulesRelative);
    if (existsSync(rulesPath)) {
      if (readFileSync(rulesPath, 'utf8') !== rulesContent) {
        fail(
          `${rulesRelative}: differs from the generated output — npm scripts changed without ` +
            'regenerating; rerun node scripts/bootstrap-codex-env.mjs --force.',
        );
      }
      checkRulesWithCodex(rulesPath);
    }
  } else {
    writeManaged('.codex/config.toml', CONFIG_TOML);
    writeManaged('.codex/hooks.json', HOOKS_JSON);
    writeManaged(rulesRelative, rulesContent);
    if (!existsSync(path.join(repoRoot, '.codex/environments/environment.toml'))) {
      writeManaged('.codex/environments/environment.toml', renderEnvironmentToml(repoName));
    } else {
      note('.codex/environments/environment.toml: exists, left untouched');
    }
  }

  for (const line of notes) console.log(`- ${line}`);
  if (problems.length > 0) {
    console.error('\nProblems:');
    for (const problem of problems) console.error(`- ${problem}`);
  }

  console.log(`
Manual steps (cannot be automated; once per user+machine):
1. Trust the project so the .codex/ layer loads: open it once in Codex and
   accept the trust prompt, or add to ~/.codex/config.toml:
     [projects."${repoRoot}"]
     trust_level = "trusted"
2. Trust the repo hook once: run /hooks inside a Codex session and approve the
   process-guard PreToolUse hook (trust is hash-pinned; re-approve after edits).
3. Desktop settings: cap worktree retention (Settings > Worktrees) and confirm
   the worktree root has disk headroom.
4. Codex cloud (if used): mirror .codex/environments/environment.toml [setup]
   at chatgpt.com/codex/settings/environments; cloud containers are externally
   capped (~8 GB) and do not read the repo environment file.
5. Verify in a live session: ask Codex to run \`npx playwright test\` — it must
   be refused (execpolicy forbidden or hook deny), then \`npm test\` — it must
   run guarded (.guard/last-run.json updates).`);

  process.exit(problems.length > 0 ? 1 : 0);
}

await main();
